/**
 * Confirm cancel of a tinymce dialog
 *
 * Author: Kristiyan
 * Date : 27/11/2019
 */

tinymce.PluginManager.add('confirmcancel', function (editor, url) {
	editor.addCommand('cmdConfirmCancel', function () {
    apprise(RS.msg("legacyjs.tinymce.confirmCancel.message"), {
      confirm: true, 
      textOk: RS.msg("legacyjs.tinymce.confirmCancel.confirmYes"),
      textCancel: RS.msg("legacyjs.tinymce.confirmCancel.confirmNo")
    }, function () { editor.windowManager.close(); });
	});
});